with open(bakeries_file, "r", encoding="utf-8") as f:
    lines = f.readlines()

for idx, line in enumerate(lines):
    if idx == 0: continue
    parts = line.split("\t")
    name = parts[0]
    for k, v in new_data.items():
        if v[0] == name:
            t = v
            search_key = t[13]
            links = real_links.get(search_key, [])
            links_str = "|".join(links) if links else ""
            
            compiled_line = "\t".join([
                t[0], t[1], t[2], t[3], t[4], t[5], t[6], t[7],
                t[8], t[9], links_str, t[10], t[11], t[12]
            ]) + "\n"
            
            lines[idx] = compiled_line

with open(bakeries_file, "w", encoding="utf-8") as f:
    f.writelines(lines)

